var userConnection = Get<UserConnection>("UserConnection");
var commonInventoryService = new CommonInventoryService(userConnection);

string brnno = Get<string>("brnno");
string city = Get<string>("city");
string contactno = Get<string>("contactno");
string name1 = Get<string>("name1");
string country = Get<string>("country");
string deliveryaddr1 = Get<string>("deliveryaddr1");
string postcode = Get<string>("postcode");
string saleschannel = Get<string>("saleschannel");
string statecode = Get<string>("statecode");
string storeid = Get<string>("storeid");
string orderno = Get<string>("orderno");
string reservationid = Get<string>("reservationid");
string itemlistJson = Get<string>("itemlist");
Guid lineDetailId = Get<Guid>("LineDetailId");

try {
    var itemlist = JsonConvert.DeserializeObject<List<itemlist>>(itemlistJson);

    var createDeliveryRequest = new CreateDeliveryRequest
    {
        requestBody = new requestBodyCD
        {
            brnno = brnno,
            city = city,
            contactno = contactno,
            name1 = name1,
            country = country,
            deliveryaddr1 = deliveryaddr1,
            postcode = postcode,
            saleschannel = saleschannel,
            statecode = statecode,
            storeid = storeid,
            orderno = orderno,
            reservationid = reservationid,
            itemlist = itemlist
        }
    };

    var createDeliveryOrder = commonInventoryService.CreateDeliveryOrder(createDeliveryRequest).GetAwaiter().GetResult();
    Set("Result", JsonConvert.SerializeObject(createDeliveryOrder, Formatting.Indented));
} catch (Exception e) {
    Set("Result", e.Message);
    return false;
}

return true;
